import sys

class Solution:
    def solve(self, nums: list[int], m: int) -> int:
        # binary search between max(nums) and sum(nums)
        lo = max(nums)
        hi = sum(nums)
        def can_split(limit: int) -> bool:
            parts = 1
            cur = 0
            for x in nums:
                if cur + x > limit:
                    parts += 1
                    cur = x
                    if parts > m:
                        return False
                else:
                    cur += x
            return True
        while lo < hi:
            mid = (lo + hi) // 2
            if can_split(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

