#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& nums, int m) {
        long long lo = *max_element(nums.begin(), nums.end());
        long long hi = accumulate(nums.begin(), nums.end(), 0LL);
        auto can_split = [&](long long limit) {
            int parts = 1;
            long long cur = 0;
            for (int x : nums) {
                if (cur + x > limit) {
                    ++parts;
                    cur = x;
                    if (parts > m) return false;
                } else {
                    cur += x;
                }
            }
            return true;
        };
        while (lo < hi) {
            long long mid = (lo + hi) / 2;
            if (can_split(mid)) hi = mid;
            else lo = mid + 1;
        }
        return (int)lo;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) cin >> nums[i];
    int m;
    if (!(cin >> m)) return 0;
    Solution sol;
    int ans = sol.solve(nums, m);
    cout << ans << "\n";
    return 0;
}
